namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Room { get; set; } = "";
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = new();
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their impact on civilization." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in distributed systems and cloud computing. She has published over 50 papers and holds 3 patents in fault-tolerant systems.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Wilson", Title = "Associate Professor of Mathematics", Bio = "Dr. Wilson's research focuses on combinatorics and graph theory. He received the Distinguished Teaching Award in 2023.", Email = "j.wilson@university.edu" },
            new() { Id = 3, Name = "Prof. Maria Lopez", Title = "Professor of English", Bio = "Prof. Lopez is an acclaimed author and literary critic specializing in contemporary American fiction and creative writing pedagogy.", Email = "m.lopez@university.edu" },
            new() { Id = 4, Name = "Dr. Robert Kim", Title = "Professor of Physics", Bio = "Dr. Kim leads the university's quantum optics lab and has contributed to breakthrough research in photonic computing.", Email = "r.kim@university.edu" },
            new() { Id = 5, Name = "Dr. Emily Torres", Title = "Associate Professor of History", Bio = "Dr. Torres is an expert in Latin American history and digital humanities, bridging technology and historical research.", Email = "e.torres@university.edu" },
            new() { Id = 6, Name = "Dr. Alan Patel", Title = "Assistant Professor of Computer Science", Bio = "Dr. Patel specializes in machine learning and natural language processing with a focus on ethical AI development.", Email = "a.patel@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Room = "Science Hall 201", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "Advanced study of data structures including trees, graphs, and hash tables. Algorithm design and analysis with emphasis on time and space complexity.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", Room = "Science Hall 305", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = false },
            new() { Id = 3, Code = "CS 420", Title = "Machine Learning", Description = "Introduction to machine learning concepts including supervised and unsupervised learning, neural networks, and model evaluation techniques.", Credits = 3, Schedule = "Mon/Wed 2:00–3:30 PM", Room = "Tech Building 110", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[5], IsFeatured = true },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, and eigenvalues. Essential for advanced mathematics and computer science.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Math Building 101", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = false },
            new() { Id = 5, Code = "MATH 301", Title = "Discrete Mathematics", Description = "Covers logic, sets, combinatorics, graph theory, and number theory. Critical foundation for computer science and cryptography.", Credits = 3, Schedule = "Tue/Thu 1:00–2:30 PM", Room = "Math Building 203", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 6, Code = "ENG 110", Title = "Academic Writing", Description = "Develop critical reading and writing skills for academic contexts. Focus on argumentation, research methods, and clear prose style.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Room = "Humanities 405", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 7, Code = "ENG 250", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, exploring themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "Tue/Thu 3:00–4:30 PM", Room = "Humanities 302", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to physics with laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", Room = "Physics Lab 100", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 9, Code = "PHYS 310", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Tue/Thu 9:00–10:30 AM", Room = "Physics Lab 210", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = false },
            new() { Id = 10, Code = "HIST 101", Title = "World Civilizations", Description = "Survey of major world civilizations from antiquity to the modern era, examining political, cultural, and economic developments.", Credits = 3, Schedule = "Mon/Wed 10:00–11:30 AM", Room = "Liberal Arts 120", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = false },
            new() { Id = 11, Code = "HIST 350", Title = "Digital History", Description = "Explore how digital tools and methods are transforming historical research, from text mining to GIS mapping and digital archives.", Credits = 3, Schedule = "Wed 6:00–9:00 PM", Room = "Liberal Arts 205", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

