@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p>Explore our departments and find the courses that shape your future.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</div>

<section class="section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="badge">@course.Department.Code</span>
                <h3><a href="/courses/@course.Id">@course.Code: @course.Title</a></h3>
                <p>@course.Credits credits &middot; @course.Instructor.Name</p>
                <p class="description">@Truncate(course.Description, 100)</p>
            </div>
        }
    </div>
</section>

<section class="section">
    <h2>Departments</h2>
    <div class="dept-grid">
        @foreach (var dept in departments)
        {
            <a href="/courses?departmentId=@dept.Id" class="dept-card">
                <h3>@dept.Name</h3>
                <p>@dept.Description</p>
            </a>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="filter-bar">
    <input type="text" name="search" value="@Search" placeholder="Search courses, instructors..." class="search-input" />
    <select name="departmentId" class="dept-select">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-primary">Search</button>
</form>

@if (courses.Count == 0)
{
    <p class="no-results">No courses found. Try adjusting your search or filter.</p>
}
else
{
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-row">
                <div class="course-row-main">
                    <span class="badge">@course.Code</span>
                    <a href="/courses/@course.Id" class="course-title">@course.Title</a>
                </div>
                <div class="course-row-meta">
                    <span>@course.Credits cr</span>
                    <span>@course.Instructor.Name</span>
                    <span>@course.Schedule</span>
                </div>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist. <a href="/courses">Back to catalog</a></p>
}
else
{
    <PageTitle>@course.Code: @course.Title - University Course Catalog</PageTitle>

    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo;
        <a href="/courses?departmentId=@course.DepartmentId">@course.Department.Name</a> &rsaquo;
        <span>@course.Code</span>
    </nav>

    <article class="course-detail">
        <header>
            <h1>@course.Code: @course.Title</h1>
            <div class="detail-badges">
                <span class="badge">@course.Department.Name</span>
                <span class="badge">@course.Credits Credits</span>
            </div>
        </header>

        <section class="detail-section">
            <h2>Description</h2>
            <p>@course.Description</p>
        </section>

        <section class="detail-section">
            <h2>Schedule & Location</h2>
            <dl>
                <dt>Schedule</dt>
                <dd>@course.Schedule</dd>
                <dt>Room</dt>
                <dd>@course.Room</dd>
            </dl>
        </section>

        <section class="detail-section">
            <h2>Instructor</h2>
            <div class="instructor-card">
                <h3>@course.Instructor.Name</h3>
                <p class="instructor-title">@course.Instructor.Title</p>
                <p>@course.Instructor.Bio</p>
                <p><a href="mailto:@course.Instructor.Email">@course.Instructor.Email</a></p>
            </div>
        </section>

        <div class="enroll-cta">
            <a href="/enroll?courseId=@course.Id" class="btn-primary">Request Enrollment</a>
        </div>
    </article>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>Request Submitted</h2>
        <p>Your enrollment request has been received. You will be notified by email once it is processed.</p>
        <a href="/courses" class="btn-primary">Back to Courses</a>
    </div>
}
else
{
    <form method="post" @formname="enrollment" class="enroll-form">
        <AntiforgeryToken />

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="error-message">@errorMessage</div>
        }

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code: @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn-primary">Submit Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string? errorMessage;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? ""))
        {
            if (string.IsNullOrWhiteSpace(Model.StudentName) || string.IsNullOrWhiteSpace(Model.StudentId) || Model.CourseId == 0)
            {
                errorMessage = "Please fill in all fields.";
                return;
            }

            if (Catalog.SubmitEnrollmentRequest(Model))
            {
                submitted = true;
            }
            else
            {
                errorMessage = "Failed to submit request. Please verify your information and try again.";
            }
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }
}

