+.nav-bar { max-width: 1200px; margin: 0 auto; display: flex; align-items: center; justify-content: space-between; height: 60px; }
+.brand { color: white; font-size: 1.25rem; font-weight: 700; }
+.brand:hover { text-decoration: none; }
+.nav-links a { color: rgba(255,255,255,0.85); margin-left: 1.5rem; font-weight: 500; }
+.nav-links a:hover { color: white; text-decoration: none; }
+
+/* Main */
+.main-content { flex: 1; max-width: 1200px; margin: 0 auto; padding: 2rem; width: 100%; }
+
+/* Footer */
+.site-footer { background: var(--primary); color: rgba(255,255,255,0.7); text-align: center; padding: 1rem 2rem; }
+
+/* Hero */
+.hero { background: linear-gradient(135deg, var(--primary), var(--primary-light)); color: white; padding: 3rem 2rem; border-radius: var(--radius); text-align: center; margin-bottom: 2rem; }
+.hero h1 { margin: 0 0 0.5rem; font-size: 2.25rem; }
+.hero p { margin: 0 0 1.5rem; font-size: 1.1rem; opacity: 0.9; }
+
+/* Buttons */
+.btn-primary { display: inline-block; background: var(--accent); color: white; padding: 0.6rem 1.5rem; border-radius: var(--radius); border: none; font-size: 1rem; font-weight: 600; cursor: pointer; }
+.btn-primary:hover { background: #dd6b20; text-decoration: none; color: white; }
+
+/* Sections */
+.section { margin-bottom: 2.5rem; }
+.section h2 { margin-bottom: 1rem; color: var(--primary); }
+
+/* Course Grid (featured) */
+.course-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 1.5rem; }
+.course-card { background: var(--card-bg); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.25rem; box-shadow: var(--shadow); }
+.course-card h3 { margin: 0.5rem 0 0.25rem; font-size: 1.1rem; }
+.course-card .description { color: var(--text-muted); font-size: 0.9rem; }
+
+/* Department Grid */
+.dept-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 1rem; }
+.dept-card { display: block; background: var(--card-bg); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.25rem; box-shadow: var(--shadow); transition: border-color 0.2s; }
+.dept-card:hover { border-color: var(--primary-light); text-decoration: none; }
+.dept-card h3 { margin: 0 0 0.25rem; color: var(--primary); }
+.dept-card p { color: var(--text-muted); font-size: 0.9rem; margin: 0; }
+
+/* Badge */
+.badge { display: inline-block; background: var(--primary); color: white; font-size: 0.75rem; padding: 0.2rem 0.5rem; border-radius: 4px; font-weight: 600; }
+
+/* Filter Bar */
+.filter-bar { display: flex; gap: 0.75rem; margin-bottom: 1.5rem; flex-wrap: wrap; align-items: center; }
+.search-input, .dept-select { padding: 0.5rem 0.75rem; border: 1px solid var(--border); border-radius: var(--radius); font-size: 1rem; }
+.search-input { flex: 1; min-width: 200px; }
+
+/* Course List */
+.course-list { display: flex; flex-direction: column; gap: 0.5rem; }
+.course-row { background: var(--card-bg); border: 1px solid var(--border); border-radius: var(--radius); padding: 1rem 1.25rem; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 0.5rem; }
+.course-row-main { display: flex; align-items: center; gap: 0.75rem; }
+.course-title { font-weight: 600; font-size: 1.05rem; }
+.course-row-meta { display: flex; gap: 1.5rem; color: var(--text-muted); font-size: 0.9rem; }
+.no-results { color: var(--text-muted); font-style: italic; }

+/* Course Detail */
+.breadcrumb { color: var(--text-muted); margin-bottom: 1rem; font-size: 0.9rem; }
+.breadcrumb a { color: var(--primary-light); }
+.course-detail header { margin-bottom: 1.5rem; }
+.course-detail h1 { margin: 0 0 0.5rem; }
+.detail-badges { display: flex; gap: 0.5rem; }
+.detail-section { margin-bottom: 1.5rem; padding-bottom: 1.5rem; border-bottom: 1px solid var(--border); }
+.detail-section h2 { font-size: 1.1rem; color: var(--primary); margin-bottom: 0.5rem; }
+.detail-section dl { display: grid; grid-template-columns: auto 1fr; gap: 0.25rem 1rem; }
+.detail-section dt { font-weight: 600; }
+.instructor-card { background: var(--bg); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.25rem; }
+.instructor-card h3 { margin: 0 0 0.25rem; }
+.instructor-title { color: var(--text-muted); margin: 0 0 0.75rem; font-style: italic; }
+.enroll-cta { margin-top: 2rem; }
+
+/* Enrollment Form */
+.enroll-form { max-width: 500px; }
+.form-group { margin-bottom: 1.25rem; }
+.form-group label { display: block; font-weight: 600; margin-bottom: 0.25rem; }
+.form-group input, .form-group select { width: 100%; padding: 0.5rem 0.75rem; border: 1px solid var(--border); border-radius: var(--radius); font-size: 1rem; }
+.success-message { background: #c6f6d5; border: 1px solid #9ae6b4; border-radius: var(--radius); padding: 1.5rem; }
+.success-message h2 { color: #276749; margin: 0 0 0.5rem; }
+.error-message { background: #fed7d7; border: 1px solid #feb2b2; border-radius: var(--radius); padding: 0.75rem 1rem; margin-bottom: 1rem; color: #c53030; }
